def log(func):
    def wrapper(*args, **kwargs):
        print("before")
        result = func(*args, **kwargs)
        print("after")
        return result
    return wrapper

@log
def add(a, b):
    return a + b

print(add(2, 3))

def deco(f):
    def wrapper(*args, **kwargs):
        return f(*args, **kwargs)
    return wrapper

@deco
def greet():
    pass

print(greet.__name__)

def deco(f):
    def wrapper(*args, **kwargs):
        f(*args, **kwargs)
    return wrapper

@deco
def add(a, b):
    return a + b

print(add(2, 3))

def deco(f):
    print("decorating", f.__name__)
    return f

@deco
def foo():
    pass

print("done")
